// カスタムチェック例外
// InsufficientBalanceExceptionクラスの定義
public class InsufficientBalanceException extends Exception {

    private final int balance;
    private final int amount;

    public InsufficientBalanceException(int balance, int amount) {
        super("残高不足です。残高: " + balance + "円, 要求: " + amount + "円");
        this.balance = balance;
        this.amount = amount;
    }

    // getBalanceメソッドの定義
    public int getBalance() { return balance; }
    // getAmountメソッドの定義
    public int getAmount()  { return amount; }
}

// 使用例
// BankAccountクラスの定義
public class BankAccount {
    private int balance;

    public void withdraw(int amount) throws InsufficientBalanceException {
        // 条件分岐
        if (amount > balance) {
            // 例外を投げる
            throw new InsufficientBalanceException(balance, amount);
        }
        balance -= amount;
    }
}

// 呼び出し側
// 例外が発生する可能性がある処理
try {
    account.withdraw(10000);
} catch (InsufficientBalanceException e) {
    System.out.println(e.getMessage());
    System.out.println("不足額: " + (e.getAmount() - e.getBalance()) + "円");
}

// カスタム非チェック例外
public class UserNotFoundException extends RuntimeException {

    private final String userId;

    public UserNotFoundException(String userId) {
        super("ユーザーが見つかりません: " + userId);
        this.userId = userId;
    }

    public String getUserId() { return userId; }
}

// 使用例（throwsの宣言は不要）
public User findUser(String id) {
    User user = userMap.get(id);
    if (user == null) {
        throw new UserNotFoundException(id);
    }
    return user;
}

// チェック例外 vs 非チェック例外の使い分け:
//
// チェック例外（extends Exception）:
//  → 呼び出し側で必ず処理してほしい場合
//  → 例: ファイル不在、ネットワークエラー、残高不足
//
// 非チェック例外（extends RuntimeException）:
//  → プログラムのバグや不正な引数を示す場合
//  → 例: 存在しないID指定、不正な状態遷移

// 例外チェーン: 低レベル例外を高レベル例外でラップ
public class DataAccessException extends RuntimeException {
    public DataAccessException(String message, Throwable cause) {
        super(message, cause);
    }
}

// DBの低レベル例外をアプリ固有の例外に変換
public User findUser(int id) {
    try {
        // DB操作
        return userDao.findById(id);
    } catch (SQLException e) {
        // SQLExceptionをDataAccessExceptionでラップ
        throw new DataAccessException("ユーザー取得エラー: ID=" + id, e);
    }
}

// 呼び出し側
try {
    User user = findUser(1);
} catch (DataAccessException e) {
    System.out.println(e.getMessage());       // "ユーザー取得エラー: ID=1"
    System.out.println(e.getCause());          // java.sql.SQLException: ...
    e.printStackTrace(); // 両方のスタックトレースが表示される
}

