// UserValidatorクラスの定義
public class UserValidator {

    // validateメソッドの定義
    public static void validate(String name, int age, String email) {
        // 個別チェック → 具体的なメッセージ
        // 条件分岐
        if (name == null || name.isBlank()) {
            // 例外を投げる
            throw new IllegalArgumentException("名前は必須です");
        }
        if (name.length() > 50) {
            // 例外を投げる
            throw new IllegalArgumentException(
                "名前は50文字以内です（入力: " + name.length() + "文字）");
        }
        if (age < 0 || age > 150) {
            // 例外を投げる
            throw new IllegalArgumentException(
                "年齢は0〜150の範囲です（入力: " + age + "）");
        }
        if (!email.contains("@")) {
            // 例外を投げる
            throw new IllegalArgumentException(
                "メール形式が不正です: " + email);
        }
    }
}

// 呼び出し側
// 例外が発生する可能性がある処理
try {
    UserValidator.validate(name, age, email);
    userService.register(name, age, email);
    System.out.println("登録完了");
} catch (IllegalArgumentException e) {
    System.out.println("入力エラー: " + e.getMessage());
}

// fetchWithRetryメソッドの定義
public static String fetchWithRetry(String url, int maxRetries) {
    Exception lastException = null;

    // 繰り返し処理（for文）
    for (int attempt = 1; attempt <= maxRetries; attempt++) {
        // 例外が発生する可能性がある処理
        try {
            HttpClient client = HttpClient.newHttpClient();
            HttpRequest req = HttpRequest.newBuilder()
                .uri(URI.create(url)).build();
            HttpResponse<String> resp = client.send(
                req, HttpResponse.BodyHandlers.ofString());
            return resp.body(); // 成功
        } catch (IOException | InterruptedException e) {
            lastException = e;
            System.out.printf("リトライ %d/%d: %s%n",
                attempt, maxRetries, e.getMessage());
            // 例外が発生する可能性がある処理
            try {
                Thread.sleep(1000L * attempt); // 待機時間を徐々に延長
            } catch (InterruptedException ie) {
                Thread.currentThread().interrupt();
                // 例外を投げる
                throw new RuntimeException("リトライ中断", ie);
            }
        }
    }
    // 例外を投げる
    throw new RuntimeException(
        maxRetries + "回リトライしましたが失敗しました", lastException);
}

